INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:friends','{"page":1,"results":[{"adult":false,"backdrop_path":"/ykDYy50mHU52PqYEu4xiFFOw5mw.jpg","genre_ids":[35],"id":1668,"origin_country":["US"],"original_language":"en","original_name":"Friends","overview":"Six young people from New York City, on their own and struggling to survive in the real world, find the companionship, comfort and support they get from each other to be the perfect antidote to the pressures of life.","popularity":143.3595,"poster_path":"/2koX1xLkpTQM4IZebYvKysFW1Nh.jpg","first_air_date":"1994-09-22","name":"Friends","vote_average":8.4,"vote_count":8964},{"adult":false,"backdrop_path":"/xHjRfQIRlxug491JrKiEYl9vHM1.jpg","genre_ids":[16,10765],"id":69500,"origin_country":["JP"],"original_language":"ja","original_name":"夏目友人帳","overview":"Natsume Takashi has the ability to see spirits, which he has long kept secret. However, once he inherits a strange book that belonged to his deceased grandmother, Reiko, he discovers the reason why spirits surround him.","popularity":47.0935,"poster_path":"/4IAX5fgsyj9SnV2sqEh5JfuOvUo.jpg","first_air_date":"2008-07-08","name":"Natsume''s Book of Friends","vote_average":8.158,"vote_count":98},{"adult":false,"backdrop_path":"/hHMWfDlqKisD5zVcZfz3KEw5U3v.jpg","genre_ids":[18,10751],"id":50821,"origin_country":["HU"],"original_language":"hu","original_name":"Barátok közt","overview":"Miklós introduces viewers into the world of Money and Charm.","popularity":8.86,"poster_path":"/kBBbSgNchtMvsgD6z1oI1RRluHP.jpg","first_air_date":"1998-10-26","name":"Among Friends","vote_average":3.4,"vote_count":19},{"adult":false,"backdrop_path":null,"genre_ids":[18],"id":20813,"origin_country":["US"],"original_language":"en","original_name":"Friends","overview":"Friends is a short-lived kids-oriented drama that aired in the spring of 1979. The series, which was produced by Aaron Spelling and aired on ABC, starred Charlie Aiken, Jill Whelan, and Jarrod Johnson as three Southern Californian 11-year-olds. Karen Morrow also appeared. Only five one-hour episodes were produced before the series was cancelled.","popularity":1.4992,"poster_path":"/ogRWiG361aZsRe0M35iou9E7nq6.jpg","first_air_date":"1979-03-25","name":"Friends","vote_average":5,"vote_count":1},{"adult":false,"backdrop_path":null,"genre_ids":[35],"id":44333,"origin_country":[],"original_language":"en","original_name":"Carol Burnett and Friends","overview":"Carol Burnett and Friends was a syndicated, truncated version of The Carol Burnett Show, showing only the sketches.The show star''s Carol Burnett and co-star''s Tim Conway and Harvey Korman, Carol Burnett''s related shows: The Carol Burnett Show Carol Burnett and Company The Carol Burnett Show (1991) Carol & Company","popularity":3.2678,"poster_path":null,"first_air_date":"1972-10-01","name":"Carol Burnett and Friends","vote_average":5.5,"vote_count":3},{"adult":false,"backdrop_path":"/yVIudr5ZNtFvomu6CdFGKAa3njk.jpg","genre_ids":[35,18,10766],"id":36062,"origin_country":["NL"],"original_language":"nl","original_name":"SpangaS","overview":"Best Friends follows the life of a group of friends at their high school ‘Spangalis College’. Inside and outside of school exciting and challenging experiences take place. Growing up is never easy; every character has its own, unique story of love, friendship, loneliness, sorrow, discovery. There is drama and joy in school, family, teachers, parents, divorce, bullying, and always dreams for the future.","popularity":19.9966,"poster_path":"/2bH7QQ7WQfnbt1CWiX8BE5E2V4t.jpg","first_air_date":"2007-09-03","name":"Best Friends","vote_average":3,"vote_count":8},{"adult":false,"backdrop_path":"/omL3sd4bctdEmA8aqj1zlBqRZHS.jpg","genre_ids":[16,35,10765,10762],"id":33765,"origin_country":["CA","US"],"original_language":"en","original_name":"My Little Pony: Friendship Is Magic","overview":"Journey to the enchanted land of Equestria, where unicorn Twilight Sparkle and her pals have adventures and learn valuable lessons about friendship.","popularity":64.9973,"poster_path":"/fwW7WgJIjhBsnzk87Gyh6g9187m.jpg","first_air_date":"2010-10-10","name":"My Little Pony: Friendship Is Magic","vote_average":8.16,"vote_count":717},{"adult":false,"backdrop_path":"/7a6dgajtYVxhs9VlHtLIYRBjh2p.jpg","genre_ids":[18],"id":217807,"origin_country":["TH"],"original_language":"th","original_name":"เพื่อนต้องห้าม","overview":"A group of business students running a hostel blur the lines between friendship and romance.","popularity":15.9293,"poster_path":"/iebiH6OgFrgAQA4mhhuXE3X5kGC.jpg","first_air_date":"2023-08-12","name":"Only Friends","vote_average":8.3,"vote_count":38},{"adult":false,"backdrop_path":"/d8LvQj79fgowZkX4NTZaEG3NwsH.jpg","genre_ids":[18,80],"id":241609,"origin_country":["US"],"original_language":"en","original_name":"Your Friends & Neighbors","overview":"When a financial titan suddenly finds himself divorced and jobless, he starts robbing his wealthy neighbors to stay afloat. Stealing from his own social circle strangely exhilarates him—but he gradually gets tangled in a deadly web.","popularity":63.8691,"poster_path":"/lcp63INKEsVHUly9eayx7gEEOcG.jpg","first_air_date":"2025-04-10","name":"Your Friends & Neighbors","vote_average":7.5,"vote_count":182},{"adult":false,"backdrop_path":"/5meyZ1ZcmpcKqNUr8V6IVrRBwh3.jpg","genre_ids":[16,35,18,10751,10762,10765],"id":79024,"origin_country":["JP"],"original_language":"ja","original_name":"アイカツフレンズ!","overview":"Aine Yūki is good at making friends, and is enrolled in Star Harmony Academy''s general education track. She befriends Mio Minato, the school''s top idol, and becomes an idol herself.","popularity":12.8292,"poster_path":"/pM5ND1TiH6jArgMjMbJcnGMhk5W.jpg","first_air_date":"2018-04-05","name":"Aikatsu Friends!","vote_average":8.2,"vote_count":12},{"adult":false,"backdrop_path":"/7PE919EeLS4lLaNvieRU0nIzdSa.jpg","genre_ids":[10766,18,10751],"id":12703,"origin_country":["MX","US"],"original_language":"es","original_name":"Amigos x Siempre","overview":"The story is set at a prestigious, but rigid and repressive school called Instituto Vidal. Its strict owner, Julia Vidal, was once kind but has now turned into a bitter woman following the death of her husband and her daughter, Lauriel. Her granddaughter, Ana, a very sweet and intelligent 10 year old, also has been affected by the death: She has been rendered virtually speechless by the trauma, though she expresses herself through music and possesses an extraordinary ability to move objects with her mind. Ana''s unscrupulous father, Francisco Capistrán, however, has taken advantage of the situation to try to steal Julia''s school. The timely arrival of Ana''s uncle, Salvador, Amanda and her adopted son changes everything. Ana’s sad and lonely life takes an unexpected turn for the better and she regains her joy in a series of adventures bursting with humor, excitement, music and thrilling surprises.","popularity":3.8491,"poster_path":"/5qd7lFedjUGJLD9karcAF6ZHPgV.jpg","first_air_date":"2000-01-10","name":"Friends 4 Ever","vote_average":7.5,"vote_count":6},{"adult":false,"backdrop_path":"/vwY5xvYNtZAEHjwaAYvMSeOeaOH.jpg","genre_ids":[16,35,18],"id":72508,"origin_country":["JP"],"original_language":"ja","original_name":"コンビニカレシ","overview":"Six high school boys hang out at a local convenience store where they talk about their daily lives. Haruki Mishima and Towa Honda are first year students looking forward to the high school experience. Alongside them, there’s Nasa Sanagi, the only member of the cooking research club. Natsu Asumi is a loner but has third year students, Mikado Nakajima and Masamune Sakurakoji, looking out for him.","popularity":10.6441,"poster_path":"/ghhTl889ut6MLUT7DgELl17vkTs.jpg","first_air_date":"2017-07-07","name":"Convenience Store Boy Friends","vote_average":6.6,"vote_count":13},{"adult":false,"backdrop_path":"/v4nud3g728IYbgAVxn7ldjiSO62.jpg","genre_ids":[10764],"id":259302,"origin_country":["CN"],"original_language":"zh","original_name":"花儿与少年·好友记","overview":"","popularity":7.9488,"poster_path":"/60rXKMqeM5W3HejDTZAsZ6trQJk.jpg","first_air_date":"2024-04-23","name":"Divas Hit The Road · Good Friends","vote_average":6.5,"vote_count":2},{"adult":false,"backdrop_path":"/3e7wSKDG038mOZ5Fnt18i5oj3ED.jpg","genre_ids":[10764],"id":229263,"origin_country":["CN"],"original_language":"zh","original_name":"是好朋友的周末","overview":"The program invites five groups of friends with original friendships to meet for a three-day and two-night \"true friend\" camping.","popularity":11.6691,"poster_path":"/bnhHxIDhMB93z1BfhZVguIDd6Ik.jpg","first_air_date":"2023-06-23","name":"Friends Together","vote_average":6,"vote_count":1},{"adult":false,"backdrop_path":"/bi0nnsQOE4ug5ok4eyZhROs8PPW.jpg","genre_ids":[10751,16,10759,10762],"id":33749,"origin_country":["CA","GB","US"],"original_language":"en","original_name":"Friends and Heroes","overview":"Friends and Heroes is a Christian children''s program that airs on TBN, Smile of a Child TV, and was also shown on BBC TV. The show is both traditionally animated and computer animated. It takes place from 69 - 71 AD. There are three series each of 13 Episodes: Series 1 is set in Alexandria, Egypt; Series 2 in Jerusalem and Series 3 in Rome. The series was created by Brian D. Brown and Eric J. Danenberg, who also worked on The Storykeepers.","popularity":3.9921,"poster_path":"/gOSRh3fMV18SzQzAWDEwTDraa0R.jpg","first_air_date":"2007-03-12","name":"Friends and Heroes","vote_average":10,"vote_count":2},{"adult":false,"backdrop_path":"/taa2aoX0ZBZiydrmc4p3IBtmJz0.jpg","genre_ids":[16,35],"id":217407,"origin_country":["JP"],"original_language":"ja","original_name":"男女の友情は成立する？（いや、しないっ!!）","overview":"Childhood BFFs Himari and Yu’s vow of friendship hits turbulence when Yu reunites with his first crush in high school. Himari, who’s never known the fuzzy warmth of a crush, now must confront her feelings. Their shared dreams and peaceful days as a twosome gardening club are tested in this tale of love, flowers, and growing pains!","popularity":11.9563,"poster_path":"/nAooVCW6PIfISHegaIwtQOZLBOC.jpg","first_air_date":"2025-04-04","name":"Can a Boy-Girl Friendship Survive?","vote_average":6.6,"vote_count":17},{"adult":false,"backdrop_path":"/dvDGHFUtr8J40a52KgIfG42cIqi.jpg","genre_ids":[10764],"id":239028,"origin_country":["CN"],"original_language":"zh","original_name":"快乐老友记","overview":"","popularity":9.0433,"poster_path":"/tv5YPBExl7ZFafuveJu1auttjqE.jpg","first_air_date":"2023-11-09","name":"Happy Friends","vote_average":7,"vote_count":2},{"adult":false,"backdrop_path":"/9evU2rFQIR3wic0mnIBw9UNUKbL.jpg","genre_ids":[18],"id":115479,"origin_country":["CN"],"original_language":"zh","original_name":"流金岁月","overview":"Set in 21st century Shanghai, it revolves around two women with different backgrounds and personalities who forge a deep friendship as they support each other through hard times in life.","popularity":9.4011,"poster_path":"/6h9vZk8t2PmKnn5qJPZAbtTwGlR.jpg","first_air_date":"2020-12-28","name":"My Best Friend''s Story","vote_average":7,"vote_count":5},{"adult":false,"backdrop_path":"/iMh5wkmPYgT39iL8VwFRkz82wdk.jpg","genre_ids":[16,35],"id":60730,"origin_country":["JP"],"original_language":"ja","original_name":"僕は友達が少ない","overview":"Kodaka Hasegawa has just transferred to St. Chronica''s Academy and he''s having a hard time making friends. With his naturally blond hair and fierce looking eyes, people constantly mistake him for a delinquent. One day, he runs into his bad-tempered loner of a classmate, Yozora, while she''s talking to her imaginary friend, Tomo. Since neither of them have any friends, they decide to form a club and start recruiting some. Little by little, lonely classmates join their club to learn how to build friendships through cooking together, playing games, and other group activities. But, with so many misfits, will the club members really be able to get along?","popularity":7.0127,"poster_path":"/oaKPbowjQgbNgaQsTNBlU7e00FI.jpg","first_air_date":"2011-10-07","name":"Haganai: I Don''t Have Many Friends","vote_average":7.509,"vote_count":170},{"adult":false,"backdrop_path":"/phKb3LikY8TpxVBBUUlU4RAnRJ0.jpg","genre_ids":[16,35],"id":60827,"origin_country":["JP"],"original_language":"ja","original_name":"一週間フレンズ。","overview":"High school sophomore Yūki Hase noticed that Kaori Fujimiya, his classmate, was always alone. He tried to start a conversation with her but was turned down: \"My memories of friendship can last only a week,\" she said. Despite of knowing this shocking truth, Yūki keeps trying to be Kaori''s \"new\" friend every week.","popularity":6.5623,"poster_path":"/9GUz9NEePmrEw0ULIKWBFmt6S4t.jpg","first_air_date":"2014-04-07","name":"One Week Friends","vote_average":6.6,"vote_count":36}],"total_pages":30,"total_results":587}','2026-04-07 04:20:35');
