INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:Neigh','{"page":1,"results":[{"adult":false,"backdrop_path":"/d8LvQj79fgowZkX4NTZaEG3NwsH.jpg","genre_ids":[18,80],"id":241609,"origin_country":["US"],"original_language":"en","original_name":"Your Friends & Neighbors","overview":"When a financial titan suddenly finds himself divorced and jobless, he starts robbing his wealthy neighbors to stay afloat. Stealing from his own social circle strangely exhilarates him—but he gradually gets tangled in a deadly web.","popularity":63.8691,"poster_path":"/lcp63INKEsVHUly9eayx7gEEOcG.jpg","first_air_date":"2025-04-10","name":"Your Friends & Neighbors","vote_average":7.5,"vote_count":182},{"adult":false,"backdrop_path":"/6vaxQIDlAGtELnfyBMC9toTYMuX.jpg","genre_ids":[16,35,10765],"id":295483,"origin_country":["JP"],"original_language":"ja","original_name":"悪役令嬢は隣国の王太子に溺愛される","overview":"Tiararose Lapis Clamentile is set to marry Hartknights, crown prince of Lapis Lazuli—until she suddenly remembers her past life and realizes she’s been reincarnated into her favorite game, The Ring of Lapis Lazuli, as the doomed villainess! But just as she’s about to lose hope, the crown prince of Aquasteed proposes instead. Could this unexpected turn finally lead to a happy ending of her own?","popularity":6.5782,"poster_path":"/h96XGrKnxMLns3QZVDytji37Ng6.jpg","first_air_date":"2026-01-11","name":"The Villainess Is Adored by the Prince of the Neighbor Kingdom","vote_average":6.182,"vote_count":11},{"adult":false,"backdrop_path":"/oLIEfd2h9IT46LV4vwhJ7xHWyph.jpg","genre_ids":[18,9648],"id":61089,"origin_country":["JP"],"original_language":"ja","original_name":"美しい隣人","overview":"A sudden encounter between a gracefully attractive but mysterious woman, Saki, and an ordinary housewife, Eriko, who has a happy family, causes Eriko''s serene daily life to fall apart. Eriko''s husband, Shinji becomes the target of Saki''s advances and finds himself caught between her and his wife.","popularity":7.3246,"poster_path":"/nsh5isY4F711BPPYuFgOytYQ2gN.jpg","first_air_date":"2011-01-11","name":"The Beautiful Neighbor","vote_average":6.5,"vote_count":2},{"adult":false,"backdrop_path":"/fi3F610zUye8u7HaaGYUGviZTwj.jpg","genre_ids":[10766,18,10751,35],"id":2674,"origin_country":["AU"],"original_language":"en","original_name":"Neighbours","overview":"Neighbours is an Australian television soap opera.  The show''s storylines concern the domestic and professional lives of the people who live and work in Erinsborough, a fictional suburb of Melbourne, Victoria. The series primarily centres around the residents of Ramsay Street, a short cul-de-sac, and its neighbouring areas, the Lassiters complex, which includes a bar, hotel, cafe, news office and park. Neighbours began with three families created by Watson – the Ramsays, the Robinsons and the Clarkes. Watson said that he wanted to show three families who are friends living in a small street. The Robinsons and the Ramsays had a long history and were involved in an ongoing rivalry.","popularity":25.9333,"poster_path":"/bXY78bQsKCIiD17Sr6yO4wLIXqS.jpg","first_air_date":"1985-03-18","name":"Neighbours","vote_average":5.94,"vote_count":58},{"adult":false,"backdrop_path":"/gA8gyk2PvFWp0Sto8kLbf0fllUJ.jpg","genre_ids":[18],"id":228497,"origin_country":["JP"],"original_language":"ja","original_name":"癒やしのお隣さんには秘密がある","overview":"Yomogida Fujiko is an office worker with an academic complex. She works hard and becomes a full-time employee at an insurance company, but because of her diligence, she is unable to refuse the work she is asked to do and accepts it with a smile on her face. One day, an elite company employee, Nishina Soma, moves into the room next door. Fujiko is soothed by the time she spends with her very kind and gentlemanly neighbor. But why did Nishina, a supposedly elite man, move into this shabby apartment, and why is he so kind to Fujiko...? It seems that Nishina, who does not speak much, is a stranger to Fujiko...?","popularity":5.8372,"poster_path":"/4Bh9zhG926l373WaGx3XWl1Nssq.jpg","first_air_date":"2023-07-08","name":"The Neighbor of Healing Has a Secret","vote_average":7,"vote_count":1},{"adult":false,"backdrop_path":"/d0GhwTlOdLEkTad6DvxarlTb0rQ.jpg","genre_ids":[16,35,10751,10762],"id":103577,"origin_country":["AE"],"original_language":"ar","original_name":"شعبية الكرتون","overview":"A cartoon comedy TV series in the United Arab Emirates that revolves around social and cultural values in the Emirati society.","popularity":0.8422,"poster_path":"/ly7Mndsxgm3NEkPdYGDkxGRiJAZ.jpg","first_air_date":"2006-09-23","name":"Cartoon''s Neighborhood","vote_average":7,"vote_count":5},{"adult":false,"backdrop_path":"/2GlkdaHtxORqWfPccv2YLDoLxMb.jpg","genre_ids":[35],"id":81144,"origin_country":["US"],"original_language":"en","original_name":"The Neighborhood","overview":"The nicest guy in the Midwest moves his family into a tough neighborhood in Los Angeles where not everyone appreciates his extreme neighborliness. That includes their new next-door neighbor Calvin.","popularity":22.4038,"poster_path":"/uItUViUsFAY7wzufTS2zWNbuuAm.jpg","first_air_date":"2018-10-01","name":"The Neighborhood","vote_average":7.583,"vote_count":163},{"adult":false,"backdrop_path":"/vhEioeZWXwDRh3ifeYrKD7DROvU.jpg","genre_ids":[16,35],"id":82736,"origin_country":["JP"],"original_language":"ja","original_name":"となりの吸血鬼さん","overview":"The modern-day vampire comedy centers on high school girl Amano, who was saved from a strange incident by a vampire girl named Sophie Twilight, and has been interested in her ever since. Akari arrives at her house uninvited and the two start to live together. Although a vampire, Sophie never attacks humans, but purchases blood and anime goods via mail and lives a modern life.","popularity":4.9331,"poster_path":"/An76xFiqgurA6rYDU5j0bvQZxyH.jpg","first_air_date":"2018-10-05","name":"Ms. Vampire Who Lives in My Neighborhood.","vote_average":5.7,"vote_count":25},{"adult":false,"backdrop_path":"/x19NGhXDMm8gfpH8usLMYwOhHLq.jpg","genre_ids":[16,35,18],"id":23573,"origin_country":["JP"],"original_language":"ja","original_name":"ご近所物語","overview":"Mikako Kōda is an aspiring fashion designer who attends Yazawa Art Academy in Tokyo and is slowly building up her clothing brand, Happy Berry. Having been childhood friends with her neighbor, Tsutomu Yamaguchi, since infancy, Mikako reassesses her once-platonic feelings for him when he suddenly becomes popular at school due to his resemblance to the singer Ken Nakagawa and begins dating Mariko, a popular and attractive girl.","popularity":4.8951,"poster_path":"/j07gLAV92lnJiEdtpbvVky0N1U4.jpg","first_air_date":"1995-09-10","name":"Neighborhood Story","vote_average":6.3,"vote_count":6},{"adult":false,"backdrop_path":"/zmjb2Yjb411Qjbt5A5dId9Ridc9.jpg","genre_ids":[35,10751],"id":36494,"origin_country":["SK"],"original_language":"sk","original_name":"Susedia","overview":"While married couples live side by side, but temperament, opinions and ways of life are quite different. They experience humorous situations based on misunderstandings and coincidences that life brings.","popularity":1.8288,"poster_path":"/d81pOo7Ei0T1Za6PY9mg7cWT7DA.jpg","first_air_date":"2006-09-04","name":"The Neighbours","vote_average":8.1,"vote_count":7},{"adult":false,"backdrop_path":"/jebY4q92zIO3ghfB3MnuVJ8ptie.jpg","genre_ids":[18,80],"id":61506,"origin_country":["NL"],"original_language":"nl","original_name":"Nieuwe Buren","overview":"Peter and Eva, a nice young couple expecting their first child, buy a house in a suburban village. Before they get to move into their new home, they lose their baby girl. Eva has a hard time coping with her loss. Peter has mixed feelings. The baby wasn’t his to begin with. He’s infertile and hopes the chapter of having children has now come to an end. Then they meet their new neighbors Rebecca and Steve, a carefree outgoing couple, that helps them forget their pain. But are they really who they say they are?","popularity":4.4392,"poster_path":"/uCcxI5cm1UVky3GWhf6cOBZaeXO.jpg","first_air_date":"2014-09-14","name":"New Neighbors","vote_average":5.9,"vote_count":10},{"adult":false,"backdrop_path":"/kUiiEa1nSVjeX8QPXBKLY7LqTFK.jpg","genre_ids":[80,18],"id":64801,"origin_country":["KR"],"original_language":"ko","original_name":"동네의 영웅","overview":"Baek Shi-Yoon is an ex-secret agent. He is a well-trained human weapon. Hiding his past, he buys the bar \"Neighborhood\" and runs it is as the owner. He gets close to the neighborhood regulars at his bar and sympathizes with their pain. Baek Shi-Yoon meets a young man who works as a temporary employee. The young wants to become a police officer. Baek Shi-Yoon trains the young man as a secret agent and they fight together against evil.","popularity":4.4294,"poster_path":"/aoyrRV2QJWNtwGLF7ggL2hLPqMo.jpg","first_air_date":"2016-01-23","name":"Neighborhood’s Hero","vote_average":6.3,"vote_count":10},{"adult":false,"backdrop_path":"/rMXusQJbphrh06kUvzkL75Mao5c.jpg","genre_ids":[35],"id":96425,"origin_country":["ES"],"original_language":"es","original_name":"El vecino","overview":"Javier is going through a bad patch: he can hardly make it to the end of the month, his business of T-shirts with de-motivational slogans is not quite getting the attention, and his relationship with Lola is shacking. The least thing he needed was for an alien to fall on him and transfer his powers to him before dying.","popularity":2.8456,"poster_path":"/6UXK97fEBhEq4GGNVcAX8zl78LO.jpg","first_air_date":"2019-12-31","name":"The Neighbor","vote_average":6.573,"vote_count":48},{"adult":false,"backdrop_path":"/gaJq5yt9WfT1yFrlh2AKutalrFw.jpg","genre_ids":[10751,35],"id":65881,"origin_country":["FR"],"original_language":"fr","original_name":"Nos chers voisins","overview":"Large family or recomposed, teenagers tortured by their hormones, mothers overwhelmed family, students and party rascals, pretty sexy neighbor, retired always on the lookout for a gossip ... Life and relations - sometimes friendly, sometimes tense , but always funny of a band of neighbors who cross every day, like millions of French ... In front of the landing, in the elevator, while leaving the garbage cans or leaving to work ...","popularity":4.1331,"poster_path":"/6lswwTxFiNXJB7LGmwR7smFM7gF.jpg","first_air_date":"2012-06-04","name":"Our dear neighbors","vote_average":4.5,"vote_count":14},{"adult":false,"backdrop_path":"/kkT2B2gmynoh9kZMo1gromLNeqy.jpg","genre_ids":[16,10759,10765,35],"id":138503,"origin_country":["US"],"original_language":"en","original_name":"Your Friendly Neighborhood Spider-Man","overview":"Peter Parker is on his way to becoming a hero, but his path to get there is anything but ordinary.","popularity":9.7399,"poster_path":"/kjcsNeqF52YUQ2rUBGLMHwLkxvR.jpg","first_air_date":"2025-01-29","name":"Your Friendly Neighborhood Spider-Man","vote_average":7.8,"vote_count":253},{"adult":false,"backdrop_path":"/6hYum6ycHkHD0434gCJAnlIfdrb.jpg","genre_ids":[35,18],"id":136779,"origin_country":["JP"],"original_language":"ja","original_name":"となりのチカラ","overview":"Nakagoshi Chikara is married and has two children. His family lives together at a complex in Tokyo. He introduces himself as a novelist, but he is actually a ghost writer and writes essays for famous people. He is usually busy with his writing and doing house chores, but, when he sees people who need help, he can''t ignore them. He approaches those people and asks them if they are doing okay and if they have a problem.","popularity":3.1464,"poster_path":"/6vJRq9Ux26TeW3vt0De2NEZQYaG.jpg","first_air_date":"2022-01-20","name":"Neighbor Chikara","vote_average":4.7,"vote_count":3},{"adult":false,"backdrop_path":"/4LRlNCBOcFHuYzNmrp9gkZGtpM5.jpg","genre_ids":[18],"id":59798,"origin_country":["KR"],"original_language":"ko","original_name":"이웃집 웬수","overview":"Married couple Kim Sung-jae & Yoon Ji-yeong gets divorced. Prior to their divorce, the couple had an argument and their five year old son left the house. Their child died by a car accident. The guilt from their child''s death weighted heavily on the parents and eventually they divorced because of this.\n\nAs time goes on, the ex spouses meet again as neighbors ...","popularity":2.6078,"poster_path":"/uGrB1dbnAMMqc1rzPzNt7d9tYGX.jpg","first_air_date":"2010-03-13","name":"Definitely Neighbors","vote_average":1.3,"vote_count":7},{"adult":false,"backdrop_path":"/kcwZQbDnFlQGeaT2qwggPuPVtLC.jpg","genre_ids":[35,18],"id":75165,"origin_country":["EG"],"original_language":"ar","original_name":"سابع جار","overview":"A group of middle-class neighbors who live in the same building get exposed to situations regarding their way of living. They each face their own struggles, without the knowledge of their neighbors, even when faced with particularly complex problems.","popularity":4.0929,"poster_path":"/uYFPPi5gYxN8AMNkvPRtfyJptXB.jpg","first_air_date":"2017-10-16","name":"The Seventh Neighbour","vote_average":7.8,"vote_count":4},{"adult":false,"backdrop_path":"/2bNKTp7Lw0hDZEW2d8OMOc4ieAc.jpg","genre_ids":[35,10766,10751],"id":98071,"origin_country":["KR"],"original_language":"ko","original_name":"네 이웃의 아내","overview":"Imagine a charming person moves in next door and starts flirting with you! A married couple was once very much in love. However, after spending a long time together, they have become indifferent toward one another and are desperately in need of something new. Song Ha is a competent working woman with two children, married to Sun Kyu, a narrow-minded idealist. One day, a couple moves in next door. One is Kyung Joo, a dedicated housewife who is all about housekeeping and supporting her family, and the other is her husband Sang Shik, a patriarchal man. Song Ha and Sun Kyu, who were frustrated with each other, are attracted to their new neighbors, who are totally different from their spouses. What will these couples get up to with their whirlwind of emotions? They have nowhere to run or hide! From romance to sexy comedy, mystery, and even thrilling situations!","popularity":2.3846,"poster_path":"/etDXxhvz3a10tmaLu9aVx0URl0r.jpg","first_air_date":"2013-10-14","name":"Your Neighbor''s Wife","vote_average":7,"vote_count":2},{"adult":false,"backdrop_path":"/8J9ynHEZueSmJidZqM7W1cKQgsW.jpg","genre_ids":[35,18],"id":255478,"origin_country":["PT"],"original_language":"pt","original_name":"Vizinhos para Sempre","overview":"The daily life of the residents of the \"Terraços do Glamour\" condominium, on the outskirts of Lisbon, highlights their problems with defective apartments and spoiled facilities due to the developer''s false promises.","popularity":1.5753,"poster_path":"/rZAGjl3IsQrFfR1LRukRHyKmwsy.jpg","first_air_date":"2025-01-18","name":"Neighbors Forever","vote_average":6.8,"vote_count":2}],"total_pages":8,"total_results":148}','2026-04-07 05:12:56');
