INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:Last ','{"page":1,"results":[{"adult":false,"backdrop_path":"/okFn0UU3zsebsek5w4B4du7XHHq.jpg","genre_ids":[16,10759,10765],"id":31679,"origin_country":["JP"],"original_language":"ja","original_name":"LAST EXILE","overview":"A richly romantic action-adventure fantasy, set in a world where retro-futuristic vehicles permeate the skies. Against this lavish background are the lives of young and heroic van ship sky porters - Claus and Lavie - who are forced to take on the mission to deliver a mysterious girl, Alvis, to the battle ship Silvana. Before they know it, they become entangled in an aerial adventure between two countries gripped in an eternal war of magnificent air battleships.","popularity":14.0105,"poster_path":"/eJpGLLUoc2cYI6mxobHcmBCKHwk.jpg","first_air_date":"2003-04-07","name":"Last Exile","vote_average":7.177,"vote_count":65},{"adult":false,"backdrop_path":"/gjUkdl62eBtxAl4L4Xurm5UBZ0x.jpg","genre_ids":[16,10759,10765,10768],"id":101972,"origin_country":["JP"],"original_language":"ja","original_name":"キミと僕の最後の戦場、あるいは世界が始まる聖戦","overview":"For years, a great war has raged on between the scientifically advanced Empire and a paradise of witches known as the Nebulis Sovereignty. This age-old battle sets the scene for a fateful encounter between two young combatants: an imperial swordsman, Iska, and the witch princess, Aliceliese. As sworn enemies, they vow to cut each other down in order to unite their worlds, and yet Iska finds himself entranced by her beauty and righteousness, while Aliceliese is moved by his strength and resolve. In the midst of a never-ending war that forbids them from being together, they have no choice but to destroy each other-or find another way.","popularity":27.0178,"poster_path":"/1VtaTXsHTRfh8m49OVJfMb4JVuh.jpg","first_air_date":"2020-10-04","name":"Our Last Crusade or the Rise of a New World","vote_average":8.2,"vote_count":242},{"adult":false,"backdrop_pat