INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:Pitt','{"page":1,"results":[{"adult":false,"backdrop_path":"/z3BkMbCy5ajZPMyKEUwsPHuz2cV.jpg","genre_ids":[18],"id":250307,"origin_country":["US"],"original_language":"en","original_name":"The Pitt","overview":"The staff of Pittsburgh''s Trauma Medical Center work around the clock to save lives in an overcrowded and underfunded emergency department.","popularity":103.8005,"poster_path":"/kvFSpESyBZMjaeOJDx7RS3P1jey.jpg","first_air_date":"2025-01-09","name":"The Pitt","vote_average":8.697,"vote_count":603},{"adult":false,"backdrop_path":"/wWQxEdWn5MSqVIID0vTq22Wi5LZ.jpg","genre_ids":[],"id":112374,"origin_country":["JP"],"original_language":"ja","original_name":"ぴったんこカン・カン","overview":"","popularity":2.1976,"poster_path":"/KV0Ag0oDTduaaxSePJvpQUh6LI.jpg","first_air_date":"2003-04-15","name":"Pittanko Kan Kan","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/apYa4WGxj5FQUvKwDfaJ0MR0IGy.jpg","genre_ids":[18],"id":119237,"origin_country":["IN"],"original_language":"te","original_name":"పిట్టా కథలు","overview":"Four different women, four journeys of love and betrayal. The common thread? They all want to dismantle the patriarchy.","popularity":1.7554,"poster_path":"/3yltvu4xxdLaYujjc3A0Omj8R6I.jpg","first_air_date":"2021-02-19","name":"Pitta Kathalu","vote_average":4.6,"vote_count":5},{"adult":false,"backdrop_path":"/dOj14seNbFoHfCQYLbSaKYBawLv.jpg","genre_ids":[35,18],"id":243963,"origin_country":["US"],"original_language":"en","original_name":"The Pradeeps of Pittsburgh","overview":"The Pradeeps attempt to prove their innocence to a pair of investigating government agents by recounting their initial life in America after moving from India. Though each family member has a different perspective on the events, they weave together a story of humor, heartbreak, and the often-complicated pursuit of their respective American Dreams.","popularity":3.2603,"poster_path":"/ckqyjYZim2TEC7q46ieB3WoiYl6.jpg","first_air_date":"2024-10-17","name":"The Pradeeps of Pittsburgh","vote_average":6.1,"vote_count":14},{"adult":false,"backdrop_path":null,"genre_ids":[35],"id":3682,"origin_country":["US"],"original_language":"en","original_name":"The Pitts","overview":"The Pitts is a short-lived FOX sitcom that aired 7 half-hour episodes between March and April 2003. It is about a family and their bad luck. It was a satire on typical American sitcoms with over-the-top sight gags.","popularity":3.5747,"poster_path":null,"first_air_date":"2003-03-30","name":"The Pitts","vote_average":5,"vote_count":1},{"adult":false,"backdrop_path":null,"genre_ids":[],"id":24090,"origin_country":["NL"],"original_language":"nl","original_name":"Pittige tijden","overview":"","popularity":1.7848,"poster_path":"/1ATAreFtUSlW1DtUVG0rx8aCUNf.jpg","first_air_date":"1996-09-07","name":"Pittige tijden","vote_average":8.3,"vote_count":3},{"adult":false,"backdrop_path":"/nIkoaieohLdwacMuAKRIkvA15wF.jpg","genre_ids":[10764],"id":232607,"origin_country":["US"],"original_language":"en","original_name":"Pittsburgh Steelers","overview":"Full games of the Pittsburgh Steelers by season year.","popularity":0.6484,"poster_path":"/giCzpMTK4MXRXvbWNcVzQlpvoiI.jpg","first_air_date":"","name":"Pittsburgh Steelers","vote_average":10,"vote_count":1},{"adult":false,"backdrop_path":null,"genre_ids":[99],"id":49742,"origin_country":["US"],"original_language":"en","original_name":"Previn and the Pittsburgh","overview":"Renowned composer, conductor, and pianist Andre Previn welcomes one or more musical guests for conversation and performance, either accompanied by Mr. Previn on piano or in concert with the Pittsburgh Symphony Orchestra. Produced by WQED and syndicated nationally on PBS, the series was notable among musical performance programs for its deft camera work and editing. The episode The Music That Made the Movies was nominated for an Emmy for Outstanding Music Direction.","popularity":1.3016,"poster_path":"/vEj7xjUVZ63wdDYjjJXndIIKc2e.jpg","first_air_date":"1977-02-27","name":"Previn and the Pittsburgh","vote_average":8,"vote_count":2},{"adult":false,"backdrop_path":"/wwBTgk1rlj8f6vdseRqXqj9CVXz.jpg","genre_ids":[16],"id":247881,"origin_country":["XG"],"original_language":"de","original_name":"Pittiplatsch reist ins Koboldland","overview":"","popularity":0.0439,"poster_path":"/ydG1ToG3QPijsf8yIflG4uQYsYI.jpg","first_air_date":"1972-01-01","name":"Pittiplatsch reist ins Koboldland","vote_average":10,"vote_count":1},{"adult":false,"backdrop_path":null,"genre_ids":[10762],"id":262286,"origin_country":["XG"],"original_language":"de","original_name":"Pittiplatsch","overview":"","popularity":0.0544,"poster_path":null,"first_air_date":"1962-06-17","name":"Pittiplatsch","vote_average":10,"vote_count":1},{"adult":false,"backdrop_path":"/mmFmog7kKceZ59ep9J470G4jjc5.jpg","genre_ids":[],"id":301738,"origin_country":["US"],"original_language":"en","original_name":"Pittsburgh Penguins Greatest Games","overview":"From their inception in 1967, the Pittsburgh Penguins have provided many unforgettable moments and now you can relive their greatest games. This includes the classic games that defined a franchise, as voted on by you, the fans!","popularity":0.3599,"poster_path":"/cLWW0bMzUU0MdJnHw3xMAkvEtuP.jpg","first_air_date":"1989-04-25","name":"Pittsburgh Penguins Greatest Games","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":null,"genre_ids":[99],"id":53199,"origin_country":[],"original_language":"en","original_name":"Pittsburgh Penguins: In the Room","overview":"In The Room, produced by Leo McCafferty, a three-time Emmy award winner with NFL Films, not only takes fans inside the Penguins'' locker room but also offers a peek behind the curtain at training camp, practice sessions, life on the road, community events and personal experiences of Pens players.","popularity":0.1685,"poster_path":"/xI2l6bAHaxPDZ3hy49ZcwsHApZ.jpg","first_air_date":"","name":"Pittsburgh Penguins: In the Room","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":null,"genre_ids":[],"id":84440,"origin_country":[],"original_language":"en","original_name":"NFL: Pittsburgh Steelers - Road to XLIII","overview":"This set includes the full game broadcasts for four of the 2008 Pittsburgh Steelers contests from that season including three playoff games, one of which is their season-ending triumph over the Arizona Cardinals in Super Bowl XLIII.","popularity":0.0948,"poster_path":"/6FHX1FbjmrnFp0r8Wgvsv8qZDTX.jpg","first_air_date":"2008-12-21","name":"NFL: Pittsburgh Steelers - Road to XLIII","vote_average":10,"vote_count":1},{"adult":false,"backdrop_path":null,"genre_ids":[10751,16],"id":3075,"origin_country":["FR","NL"],"original_language":"fr","original_name":"Pitt & Kantrop","overview":"Pitt & Kantrop is a children''s television programme produced by the Eurovision Network and is shown on BBC One in the United Kingdom. It follows the journey of a 13 year old boy named Pitt and his pet pterodactyl Kantrop as they adventure through the wilderness of the Stone Age eras, and solve problems in the tribe''s village. It is from the creators of Watch My Chops.","popularity":0.0404,"poster_path":"/p0wft6xJ1dPVzYU5TDVm2uKGdY9.jpg","first_air_date":"2005-02-02","name":"Pitt & Kantrop","vote_average":6,"vote_count":1},{"adult":false,"backdrop_path":null,"genre_ids":[10764],"id":20350,"origin_country":[],"original_language":"en","original_name":"Pittsburgh Penguins Confidential","overview":"Pittsburgh Penguins Confidential, sometimes called Pens Confidential, was a Pittsburgh, Pennsylvania based half-hour TV sports series that aired on various local stations throughout Western Pennsylvania, Eastern Ohio, and Northern West Virginia. Its main subject was the Pittsburgh Penguins, the National Hockey League franchise in Pittsburgh. The show ran from 1996 until 1999 and was hosted by Jake Ploeger and Jeanne Blackburn.","popularity":0,"poster_path":null,"first_air_date":"","name":"Pittsburgh Penguins Confidential","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":null,"genre_ids":[],"id":14193,"origin_country":[],"original_language":"en","original_name":"Pittsburgh''s Talking","overview":"Pittsburgh''s Talking was a live, hour-long talk show that aired on WTAE, the ABC station in Pittsburgh, Pennsylvania from January 4, 1988 until 1991. Ann Devlin served as the host.","popularity":0,"poster_path":null,"first_air_date":"","name":"Pittsburgh''s Talking","vote_average":0.5,"vote_count":1},{"adult":false,"backdrop_path":"/nsoDnZM9qPTVtY6DpMOUPIzHTsJ.jpg","genre_ids":[10767],"id":318508,"origin_country":["US"],"original_language":"en","original_name":"The Pitt Podcast","overview":"Join Dr. Alok Patel and Hunter Harris, the hosts of The Pitt Podcast, the official companion podcast of The Pitt from HBO Max. After each episode, we''ll go inside The Pitt to break down each episode with the people at the heart of the show.","popularity":0.42,"poster_path":"/v4dGVlHyChW2V5ZD4ZR03EYgnaa.jpg","first_air_date":"2026-01-09","name":"The Pitt Podcast","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/sPwMiA75SHTJf6M6GvBF9KXzQ2z.jpg","genre_ids":[99],"id":229825,"origin_country":["GB"],"original_language":"en","original_name":"Evacuation","overview":"This three-part documentary military thriller provides unprecedented access to the British Ministry of Defence as it recounts the daring operation to evacuate Kabul. It’s an emotional, unflinching series that, for the first time, shows how Britain’s largest airlift since World War II actually played out, minute by minute.","popularity":0.626,"poster_path":"/zUsvGqBa2035pBKfU87jT4dj98x.jpg","first_air_date":"2023-07-02","name":"Evacuation","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/5LRv6ZbZZBzm7c4TNQbdq4nXSyc.jpg","genre_ids":[],"id":133936,"origin_country":["GB"],"original_language":"en","original_name":"The Cotswolds With Pam Ayres","overview":"Pam Ayres sets off on a journey around the part of Britain she calls home – the Cotswolds. On her travels, she unearths the familiar and not so familiar gems this beautiful part of the country has to offer.","popularity":0.4091,"poster_path":"/dPxHPuWkV4CvOaqvW4dywUcAAlv.jpg","first_air_date":"2021-09-17","name":"The Cotswolds With Pam Ayres","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/alhsBWuzR1OQewbU60vPy9NIrGs.jpg","genre_ids":[],"id":270676,"origin_country":["SE"],"original_language":"sv","original_name":"The Cotswolds and Beyond With Pam Ayres","overview":"","popularity":0.0214,"poster_path":"/sxHwIO7lnHJh529I8uqt5bXhRGF.jpg","first_air_date":"2024-09-01","name":"The Cotswolds and Beyond With Pam Ayres","vote_average":0,"vote_count":0}],"total_pages":1,"total_results":20}','2026-04-07 05:57:48');
