INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:Andie','{"page":1,"results":[{"adult":false,"backdrop_path":null,"genre_ids":[18],"id":215621,"origin_country":["PH"],"original_language":"tl","original_name":"Si Andy, Si Lauren, O Si Peng?","overview":"It''s a story about three cousins who grew up with their uncle, Papang He, the youngest of the Magbanua siblings. Their fathers are seamen and they have lived in different countries and some of them already have families there. Coby will come into their lives, the guy that will test their masculinity and gender identity, will seduce, spread and bring conflicts to each other because his main goal is... revenge. With Coby on vacation at the rest house are his two friends, Angel and BJ, collectively known as ABC Boys. Andy, Lauren and Peng will compete with one another to win Coby''s love until eventually only one will be victorious. Coby will find out who took advantage of him but in the end, love will still prevail. It''s a story about family, acceptance, second chances and love, that love is love in any form. Who is the real Magbanua? Who is really the protagonist? Who is the villain? Who will be loved? And who can''t be chosen? Andy, Lauren, or Peng?","popularity":0.1358,"poster_path":"/m977zw7pczUSl6nTsWHNtWcYj8b.jpg","first_air_date":"2022-12-03","name":"Andy, Lauren, or Peng?","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/7pccacXza7SI0SHiTMidZXbR9t4.jpg","genre_ids":[10764,99],"id":94757,"origin_country":["BE"],"original_language":"nl","original_name":"Andy op Patrouille","overview":"Andy Peelman is not only an actor, but also a real police officer. In Andy on Patrol he visits foreign colleagues.","popularity":0.0572,"poster_path":"/1su1HNcclWeSfA0b2bHB7vuj2g8.jpg","first_air_date":"2019-10-15","name":"Andy on Patrol","vote_average":7,"vote_count":2},{"adult":false,"backdrop_path":"/ha3fjXoO96L94xBVyxPIpWXUgI6.jpg","genre_ids":[99],"id":249035,"origin_country":["GB"],"original_language":"en","original_name":"Andi Oliver’s Fabulous Feasts","overview":"Andi Oliver uses her passion for parties to create eight fabulous feasts, which unite communities and tell the incredible story of the people and places she visits.","popularity":0.1829,"poster_path":"/kjbzS2B1RDfdUWj9Z19M37sa1Rn.jpg","first_air_date":"2024-03-27","name":"Andi Oliver’s Fabulous Feasts","vote_average":1,"vote_count":1},{"adult":false,"backdrop_path":null,"genre_ids":[10763],"id":7840,"origin_country":[],"original_language":"en","original_name":"An Là","overview":"An Là is a Scottish Gaelic-language news programme broadcast on the Gaelic-language channel, BBC Alba. The programme, based at BBC Alba''s newsroom in Inverness, began at 8pm on Monday 22 September 2008 and provides a 30-minute bulletin of Scottish, British and international news for Gaelic speakers on weeknights. The Sunday night review programme, composed of highlights from the week''s bulletins as well as material from Eòrpa, called Seachd Là, began at 6.30pm on Sunday 28 September 2008.\n\nAn Là is presented from Studio G at the BBC in Inverness, but output through Studio C Gallery in BBC Pacific Quay. Seachd Là, weather and the An Là sports news all come from BBC Pacific Quay in Glasgow.\n\nAn Là is the first daily television news programme to be broadcast in Scots Gaelic since the axing of Grampian Television''s Telefios bulletins in 2000.\n\nAn Là was shortlisted in the Best Current Affairs category at the 2009 Celtic Media Festival.","popularity":0.1169,"poster_path":null,"first_air_date":"","name":"Andy''s Prehistoric Adventures","vote_average":0.5,"vote_count":1},{"adult":false,"backdrop_path":"/kUUsQZKL1nErsvb28VRDz7YZtbO.jpg","genre_ids":[99],"id":94598,"origin_country":["DE"],"original_language":"es","original_name":"Andes mágicos","overview":"From Argentina to Colombia, this stunning documentary follows five characters who share their deep connection to South America''s majestic mountains.","popu