INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:Bear','{"page":1,"results":[{"adult":false,"backdrop_path":"/mZmxNM7XMMT1QroznAQWmRf7duP.jpg","genre_ids":[16,10751,10762,35],"id":46080,"origin_country":["RU"],"original_language":"ru","original_name":"Маша и Медведь","overview":"Masha is an energetic three-year-old who can’t seem to keep herself out of trouble. Bear is a warm, fatherly figure that does his best to guide his friend and keep her from harm, often ending up the unintended victim of her misadventures.","popularity":32.6911,"poster_path":"/wPkeRunw71Mm10xQYKAwGG0NLgt.jpg","first_air_date":"2009-01-07","name":"Masha and the Bear","vote_average":6.9,"vote_count":414},{"adult":false,"backdrop_path":"/jPimk8gzcIgpxJ87deqyZ5qUp91.jpg","genre_ids":[16,10762],"id":121848,"origin_country":["CN"],"original_language":"zh","original_name":"熊出没之探险日记","overview":"","popularity":14.6021,"poster_path":"/apWYmPNXJ2QSDRrNOPpJ9SeMMNJ.jpg","first_air_date":"2017-11-28","name":"Boonie Bears: The Adventurers","vote_average":8.3,"vote_count":3},{"adult":false,"backdrop_path":"/iF7igCcBrVEW77JNBSnThXpwu9g.jpg","genre_ids":[16,35,10759,10765],"id":97782,"origin_country":["JP"],"original_language":"ja","original_name":"くまクマ熊ベアー","overview":"Fifteen-year-old Yuna prefers staying home and obsessively playing her favorite VRMMO to doing anything else, including going to school. When a strange new update gives her a one-of-a-kind bear outfit that comes with overpowered abilities, Yuna is torn: the outfit is unbearably cute, but too embarrassing to wear in-game. But then she suddenly finds herself transported into the world of the game, facing down monsters and magic for real, and the bear suit becomes the best weapon she has!","popularity":12.5779,"poster_path":"/otTmAAD7VTTcwBaR5YsKUSbqTsj.jpg","first_air_date":"2020-10-07","name":"Kuma Kuma Kuma Bear","vote_average":7.2,"vote_count":46},{"adult":false,"backdrop_path":"/sgR3BjAOcpyxV9Rq7l1BGm3fXQ8.jpg","genre_ids":[10751,35,16,10762],"id":63401,"origin_country":["US"],"original_language":"en","original_name":"We Bare Bears","overview":"Three brother bears awkwardly attempt to find their place in civilized  society, whether they''re looking for food, trying to make human friends,  or scheming to become famous on the internet. Grizzly, Panda and Ice  Bear stack atop one another when they leave their cave and explore the  hipster environs of the San Francisco Bay Area, and it''s clear the  siblings have a lot to learn about a technologically driven world. By  their side on many adventures are best friend Chloe (the only human  character in the cast), fame-obsessed panda Nom Nom, and Charlie, aka  Bigfoot.","popularity":36.8362,"poster_path":"/3xWzlLZ0kAD6SkVZTekFM9lxZyP.jpg","first_air_date":"2015-08-24","name":"We Bare Bears","vote_average":7.7,"vote_count":1831},{"adult":false,"backdrop_path":"/hz9kBQ8RxOxk2c0WN4ObgIQcgug.jpg","genre_ids":[10762,16,35],"id":202329,"origin_country":["CN"],"original_language":"zh","original_name":"熊出没","overview":"Starring two bears, Briar and Bramble, who continuously try to stop Logger Vick from cutting down trees in their forest. Vick constantly tries to carry out his job as a woodcutter, only to be hilariously outwitted by the bears.","popularity":11.9627,"poster_path":"/glbw6KUAzTZgNiCZPQC0j2rBcGL.jpg","first_air_date":"2012-01-22","name":"Boonie Bears","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/ocNm2Nlxc9qNBRl2rlqK1XW6Tzn.jpg","genre_ids":[16,10762],"id":106221,"origin_country":["CN"],"original_language":"zh","original_name":"熊出没之秋日团团转","overview":"","popularity":6.0435,"poster_path":"/vuO393tUHR5S2TGioXX0dvoqnBs.jpg","first_air_date":"2016-06-09","name":"Boonie Bears: Autumn Awesomeness","vote_average":8,"vote_count":1},{"adult":false,"backdrop_path":"/jnY9e8G8KHkkqUUxzMr64mcnWLO.jpg","genre_ids":[16,35],"id":45856,"origin_country":["JP"],"original_language":"ja","original_name":"しろくまカフェ","overview":"Pushed by his mother to stop lazing around the house, a Panda searches for a part-time job but has troubling finding one to accommodate his laziness. He soon stumbles upon the Shirokuma Cafe, run by a Polar Bear who is holding interviews for a part-time position with his faithful customer Penguin. Panda applies for the job but fails the interview, with the job instead going to a human girl named Sasako. However, the others soon point Panda towards a part-time job at a nearby zoo.","popularity":5.61,"poster_path":"/hbbeiV0BH6BFQ3VFvOIj0rXOup4.jpg","first_air_date":"2012-04-05","name":"Polar Bear Cafe","vote_average":7.8,"vote_count":12},{"adult":false,"backdrop_path":"/1MFi9LXsrFqaJDZZykJlB6AouB9.jpg","genre_ids":[35,9648],"id":69308,"origin_country":["US"],"original_language":"en","original_name":"Where the Bears Are","overview":"A comedy mystery web-series that follows the exploits of three gay bear roommates living together in Los Angeles, as they attempt to solve the murder of a party guest that turned up dead in their bathtub.","popularity":3.7317,"poster_path":"/sKcb1qDw14txcYvXktWcJIQhYSC.jpg","first_air_date":"2012-08-01","name":"Where the Bears Are","vote_average":5.5,"vote_count":4},{"adult":false,"backdrop_path":"/wHNwlE6ftEpgjVbdhLXOtv1hLs0.jpg","genre_ids":[18,35],"id":136315,"origin_country":["US"],"original_language":"en","original_name":"The Bear","overview":"Carmy, a young fine-dining chef, comes home to Chicago to run his family sandwich shop. As he fights to transform the shop and himself, he works alongside a rough-around-the-edges crew that ultimately reveal themselves as his chosen family.","popularity":36.8377,"poster_path":"/eKfVzzEazSIjJMrw9ADa2x8ksLz.jpg","first_air_date":"2022-06-23","name":"The Bear","vote_average":8.2,"vote_count":1651},{"adult":false,"backdrop_path":"/gH3HCoEBuiLqzZii0sOMfMyXSR8.jpg","genre_ids":[16],"id":204269,"origin_country":["JP"],"original_language":"ja","original_name":"森のくまさん、冬眠中。","overview":"Nowa, a bear living in the forest, decides to take an abandoned puppy under his wing. He names it Airi and takes care of it with great care. Time passes and Nowa soon has to leave him temporarily alone in order to hibernate. Waking up several months later, he discovers that Airi has grown well into an attractive young man.","popularity":8.1568,"poster_path":"/jSRmnyrqY1wmECpCCk7jv7AGFn6.jpg","first_air_date":"2022-07-04","name":"Caressing My Hibernating Bear","vote_average":6,"vote_count":4},{"adult":false,"backdrop_path":"/lXbTLLBGfHgJkmUkpaVWiwRT3hq.jpg","genre_ids":[16,10762,35,10766],"id":103085,"origin_country":["CN"],"original_language":"zh","original_name":"熊出没之丛林总动员","overview":"Boonie Bears 3 is the third part of the TV animation \"Boonie Bears\", also translated as \"Bears in the Jungle\", \"Boonie Bears Part 3\", the animated film tells the story of Bears in the Jungle who return to the jungle after traveling around the world and see their friends in the jungle again.\n\n　　Bear is the backbone of the bear brothers, smart and witty, good at improvisation; Bear two character is simple and straightforward, impulsive, but infinitely powerful. The two bears'' biggest enemy, Baldhead, is a small, thieving logger who cuts and steals.\n\n　　The two bears are chased to the jungle and become loggers again, cutting and logging trees in the jungle that has been planned as a nature reserve. In order to stop Baldjon from destroying the forest, the jungle animals, led by Bear Big and Bear Two, and Baldjon once again launched a hilarious battle.","popularity":6.6366,"poster_path":"/aAq9AAFkfZjtxJGLw4v9mtfsOm5.jpg","first_air_date":"","name":"Boonie Bears: Forest Frenzy","vote_average":7.2,"vote_count":4},{"adult":false,"backdrop_path":"/pv6ROdEOEplsHZupHispRPfCLiW.jpg","genre_ids":[35],"id":771,"origin_country":["GB"],"original_language":"en","original_name":"A Bear''s Tail","overview":"A sitcom from the creators of Channel 4 comedy \"Bo'' Selecta!\" written by and starring Leigh Francis. Everyone''s favourite talking bear learns to live with his new sitcom family, The Hennersons. As well as cast and celebrity cameo appearances, Leigh Francis brings to life a host of new characters, including nosey neighbour Sue Dales - a Scottish transsexual living with fellow transsexual Dave McCall - Keith Lemon, entrepreneur and lady''s man, and Asian film nerd Corey Haim.","popularity":1.324,"poster_path":"/aScDFU6YVYBiR69U7LmcsaHHmqL.jpg","first_air_date":"2005-07-08","name":"A Bear''s Tail","vote_average":7.2,"vote_count":4},{"adult":false,"backdrop_path":"/A1g8X7atNe7sjIEDJIyGbmaDfJn.jpg","genre_ids":[16,10751,35,10762],"id":117030,"origin_country":["US"],"original_language":"en","original_name":"We Baby Bears","overview":"Follow Grizz, Panda and Ice Bear – as their younger baby selves – traveling in a magical box to fantastic new worlds searching for a place to call home. Along the way, they meet new friends, learn a few lessons and discover that “home” can mean wherever they are, as long as they’re together.","popularity":26.76,"poster_path":"/cXJ1m6f8KORhoIcrPSOYap56aAe.jpg","first_air_date":"2022-01-01","name":"We Baby Bears","vote_average":7.264,"vote_count":276},{"adult":false,"backdrop_path":"/mkUZG3lUiAV8C1LeDQGPB9ptJmQ.jpg","genre_ids":[10764],"id":114984,"origin_country":["GB"],"original_language":"zh","original_name":"越野千里（中国版）","overview":"","popularity":3.3089,"poster_path":"/nPQant0Qjja8RoS80b5Ashzi4Qu.jpg","first_air_date":"2015-10-16","name":"Absolute Wild China with Bear Grylls","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":null,"genre_ids":[16],"id":253920,"origin_country":["DE"],"original_language":"de","original_name":"The little polar bear","overview":"Follows the adventures of Lars the little polar bear and his friends Lena the snow hare and Peeps the snow goose with the fun and mischief they get up to in the North Pole, all whilst making interesting discoveries along the way.","popularity":0.3402,"poster_path":"/AIwA9fKVGZKp8IN