INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:Levy','{"page":1,"results":[{"adult":false,"backdrop_path":"/kobz3t4TKPXRUGUpcV3Ic7sgLtW.jpg","genre_ids":[16,10759,10765],"id":256323,"origin_country":["JP"],"original_language":"ja","original_name":"リヴァイアサン","overview":"Set in an alternate steampunk past, an Austrian fugitive prince and a Scottish airman in disguise embark on an unexpected quest to prevent a world war.","popularity":4.4536,"poster_path":"/wIu0KWF2g2gWO482HXUQRM5ioOr.jpg","first_air_date":"2025-07-10","name":"Leviathan","vote_average":6.083,"vote_count":12},{"adult":false,"backdrop_path":"/ddafeL2xZoNaXreOnp5ZUDdRywX.jpg","genre_ids":[99],"id":137735,"origin_country":["GB"],"original_language":"en","original_name":"The Reluctant Traveller with Eugene Levy","overview":"Award-winning actor and nervous explorer Eugene Levy steps out of his comfort zone for a whirlwind tour of the world''s most beautiful and intriguing destinations.","popularity":3.4532,"poster_path":"/bcwuOg24gPxnOOpTAr6xw8epDZg.jpg","first_air_date":"2023-02-24","name":"The Reluctant Traveller with Eugene Levy","vote_average":7.4,"vote_count":35},{"adult":false,"backdrop_path":"/iO04pxGGLU8PYQGaru2kEbmM71s.jpg","genre_ids":[16,10759,10765],"id":93899,"origin_country":["JP"],"original_language":"ja","original_name":"Levius -レビウス-","overview":"With the casualties of war still haunting him, young Levius uses his prosthetic arm to take his fight into the brutal world of Mecha Boxing.","popularity":4.5066,"poster_path":"/dO7FDQmQhNvCrPdjqj5peMx1ZWQ.jpg","first_air_date":"2019-11-28","name":"Levius","vote_average":7.6,"vote_count":58},{"adult":false,"backdrop_path":"/ppakb03zOIqblmyz979yjkKfYfK.jpg","genre_ids":[16,10765,35],"id":51476,"origin_country":["JP"],"original_language":"ja","original_name":"絶対防衛レヴィアタン","overview":"The fantasy world of Aquafall is abound with water and greenery, and populated by dragons and fairies. Meteorites of evil creatures threaten all living things on the planet. The fairy Syrup assembles the Aquafall Defense Force, with three girls of the dragon clans as recruits. The story follows Syrup and the dragon girls Leviathan, Bahamut, and Jörmungandr as they work together to battle enemies and grow up.","popularity":1.9635,"poster_path":"/1kNKmSR9BJUpjrGMcgG3coIGwkp.jpg","first_air_date":"2013-04-06","name":"Leviathan: The Last Defense","vote_average":8,"vote_count":46},{"adult":false,"backdrop_path":"/tcWmJLNrXZoMUiA1b6Wbq2RKkp0.jpg","genre_ids":[18,37],"id":277905,"origin_country":["DE"],"original_language":"de","original_name":"Levi Strauss und der Stoff der Träume","overview":"Hardly any piece of clothing embodies freedom, pragmatism and individuality as much as the Bluejeans. It is considered a symbol of the \"American Dream\" and is carried from arm to rich by almost every person. Despite their popularity, very few know the history of their invention. Around 1850, the German-Jewish peddler son Levi Strauss emigrated to America with his sister due to lack of prospects and anti-Semitism in the old Franconian homeland. His brothers are already doing a dry goods store there. When the big gold rush breaks out, Levi continues to San Fransicso, where he opens a textile goods business under his own name. The demand from the gold-diggers for hard-wearing pants is high. So the bustling businessman teams up with the ingenious Latvian tailor Jacob Davis, who came up with the idea of ​​strengthening the seams of the pants with rivets. But a protection money patron dominates the port city and makes life difficult for them. And there are also difficulties with the patent.","popularity":2.418,"poster_path":"/afJ8CrUGZ2KbHPKVRMyhbMsfggn.jpg","first_air_date":"2025-01-03","name":"Call Me Levi","vote_average":7,"vote_count":1},{"adult":false,"backdrop_path":"/pVVSyByqATV0g42tGFpWIInI80r.jpg","genre_ids":[10767],"id":13724,"origin_country":["FI"],"original_language":"fi","original_name":"Levyraati","overview":"Levyraati was a Finnish television show which ran from the 1961–1992 originally on YLE and starting from 1992 on MTV3. It was based on the British Juke Box Jury.\n\nThe show was originally hosted by Jaakko Jahnukainen and for a brief period by Vesa Nuotio. However, the show was most famously hosted by Jukka Virtanen from 1980 till 1997 when the show went on a five year hiatus. For its 2002–2003 run it was hosted by Raakel Lignell and later by Ruben Stiller. The show has been on unspecified hiatus since 2005.\n\nIn the program Finnish celebrities would rate recordings and, in later years, music videos with a score from 1 to 10. With four guests in the panel the maximum score was 40 and the winning song or video would be performed during the ending credits. One of the panel members was a frequent guest placed among three weekly guests.","popularity":0.5329,"poster_path":"/93U8tLFr2IENV8jTiIj2LQdK3Pp.jpg","first_air_date":"2024-01-20","name":"Levyraati","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/lGHIWzumkXCac1IPDAEpz9fqA18.jpg","genre_ids":[99,80],"id":82399,"origin_country":["US"],"original_language":"en","original_name":"Chandra Levy: An American Murder Mystery","overview":"In 2001 intern Chandra Levy vanishes. Police search the city to find the 24-year-old woman, but a powerful man hampers the search - Chandra''s alleged lover, Congressman Gary Condit. Chandra''s parents tell the harrowing tale of the desperate pursuit for their missing daughter.","popularity":0.4757,"poster_path":"/yj7Z3GUW7W7RofmYHyj8gwPSrBP.jpg","first_air_date":"2017-09-04","name":"Chandra Levy: An American Murder Mystery","vote_average":7.7,"vote_count":3},{"adult":false,"backdrop_path":"/5S4sdAGCDDMmlUmoLqSPfC2I7fu.jpg","genre_ids":[99],"id":197153,"origin_country":["IL"],"original_language":"he","original_name":"חנוך לוין: חיים שכדוגמתם לא ראינו מעולם","overview":"A 4-part series on the personal and artistic biography of Hanoch Levin, Israel''s greatest playwright and one of the sharpest, wittiest, and most ruthless minds to have existed here.","popularity":0.0071,"poster_path":"/gVwNPBQXxXcmw4F5jyQ7HSDPWVS.jpg","first_air_date":"2017-04-16","name":"Hanoch Levin: A Life We Have Never Seen Before","vote_average":0,"vote_count":0}],"total_pages":1,"total_results":8}','2026-04-07 15:59:37');
