INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:The Boys','{"page":1,"results":[{"adult":false,"backdrop_path":"/bq28ajZaoMyzEIm6REelqyqtEDZ.jpg","genre_ids":[10765,10759],"id":76479,"origin_country":["US"],"original_language":"en","original_name":"The Boys","overview":"A group of vigilantes known informally as “The Boys” set out to take down corrupt superheroes with no more than blue-collar grit and a willingness to fight dirty.","popularity":185.0451,"poster_path":"/in1R2dDc421JxsoRWaIIAqVI2KE.jpg","first_air_date":"2019-07-25","name":"The Boys","vote_average":8.437,"vote_count":11747},{"adult":false,"backdrop_path":null,"genre_ids":[35],"id":28172,"origin_country":["US"],"original_language":"en","original_name":"The Boys","overview":"The Boys is an American sitcom television series that aired from August 20 until September 17, 1993.","popularity":1.4922,"poster_path":null,"first_air_date":"1993-08-20","name":"The Boys","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/9f0tJBX1MtYkMNZwkruvLgLM8Zw.jpg","genre_ids":[10764],"id":66647,"origin_country":["JP"],"original_language":"ja","original_name":"テラスハウス Boys & Girls in the City","overview":"A new set of six men and women start their lives together under one roof. All they get is a fabulous home and a car. As always, there is no script.","popularity":2.8621,"poster_path":"/43m08RWCk7QSB1KOVEuWl47fzyo.jpg","first_air_date":"2015-10-12","name":"Terrace House: Boys & Girls in the City","vote_average":7.7,"vote_count":30},{"adult":false,"backdrop_path":"/lcD0YyuOx8SHgmMAb6BFRfFCGdF.jpg","genre_ids":[9648,10759],"id":2928,"origin_country":["US"],"original_language":"en","original_name":"The Hardy Boys / Nancy Drew Mysteries","overview":"The Hardy Boys/Nancy Drew Mysteries is a television series which aired for three seasons on ABC. The series starred Parker Stevenson and Shaun Cassidy as amateur sleuth brothers Frank and Joe Hardy, respectively, and Pamela Sue Martin as girl detective Nancy Drew.\n\nThe Hardy Boys/Nancy Drew Mysteries was unusual in that it often dealt with the characters individually, in an almost anthological style. That is, some episodes featured only the Hardy Boys and others only Nancy Drew.","popularity":12.3684,"poster_path":"/2gNO5CI1U46a7faNu5aJUEsFS6H.jpg","first_air_date":"1977-01-30","name":"The Hardy Boys / Nancy Drew Mysteries","vote_average":7.1,"vote_count":29},{"adult":false,"backdrop_path":"/kgXhHyQVPbWrmE2hvjrnLsGZBMs.jpg","genre_ids":[99],"id":210318,"origin_country":["US"],"original_language":"en","original_name":"The Boys from Brazil: Rise of the Bolsonaros","overview":"The remarkable rise of one of the world’s most controversial leaders, Jair Bolsonaro, from obscurity to the presidency of Brazil.","popularity":22.2189,"poster_path":"/sZXernSnVWGhlrAhDUDtdg3fuZn.jpg","first_air_date":"2022-09-05","name":"The Boys from Brazil: Rise of the Bolsonaros","vote_average":5.4,"vote_count":4},{"adult":false,"backdrop_path":"/AqxPqTbD77ioyBDdk39MEQq6vXL.jpg","genre_ids":[18,80],"id":234763,"origin_country":["RU"],"original_language":"ru","original_name":"Слово пацана. Кровь на асфальте","overview":"In the late 1980s, when “perestroika” was taking place in the USSR and the era of the Soviet Union was about to collapse, life became unstable and very different. The 1980s brought not only freedom, but also waves of crime on the city streets. While some young people began to ‘grow up’ on the streets, others found it difficult to find their place in this unpredictable reality. Andrey, lives with his mother and five-year-old sister. He studies at a music school and often encounters street teenagers who harass him. To protect himself, Andrey makes friends with one of these teenagers, Marat, who introduces him to gang life. Youth groups fight for every piece of territory; they defend their right to live the life, even breaking laws and promises. The only thing that matters to them is the vows they make to their gang members-brothers, with whom they confront the violence and fears of the adult world.","popularity":8.5588,"poster_path":"/fmJ2vVzaSAPvCqB79H70uMHSNr4.jpg","first_air_date":"2023-11-09","name":"The Boy''s Word: Blood on the Asphalt","vote_average":8.7,"vote_count":208},{"adult":false,"backdrop_path":"/4fVwc77cov2q9i0szzYhlkAaqza.jpg","genre_ids":[35,10759,10762,16,10751],"id":34860,"origin_country":["JP"],"original_language":"ja","original_name":"忍たま乱太郎","overview":"Rantarō, Shinbei and Kirimaru are ninja  apprentices in the Ninja Gakuen, where first grade ones are called  \"Nintamas\". They must learn  everything a ninja must know, but as for our heroes, money, food or  playing are more interesting. The series show the everyday adventures of  our heroes.","popularity":25.1455,"poster_path":"/fzNiSp0HhCthOTYu9IYWlPPa7fU.jpg","first_air_date":"1993-04-10","name":"Ninja Boy Rantaro","vote_average":6.5,"vote_count":21},{"adult":false,"backdrop_path":"/qlfRTGXx6ohMzji74XwXwhpwO0r.jpg","genre_ids":[35],"id":46005,"origin_country":["RU"],"original_language":"ru","original_name":"Реальные Пацаны","overview":"","popularity":12.9828,"poster_path":"/zRJMkNuTchBcu8QlMNFZObOhp2j.jpg","first_air_date":"2010-11-08","name":"The Real Ass Boys","vote_average":7.592,"vote_count":71},{"adult":false,"backdrop_path":"/vDqCoaMU5FUAuUs0EvL4OAUCxJk.jpg","genre_ids":[10751,18],"id":210865,"origin_country":["TR"],"original_language":"tr","original_name":"Yalı Çapkını","overview":"A young girl is forced to marry a rich groom. The groom is not only rich, but also allows himself to live without any restrictions or obligations. Will married life change his habits? And how will such a man be accepted by a good-hearted wife?","popularity":55.6956,"poster_path":"/yTHaFClgAktpHwlAJzZGftep2ok.jpg","first_air_date":"2022-09-23","name":"Golden Boy","vote_average":8.194,"vote_count":98},{"adult":false,"backdrop_path":"/5WUsnqUm7xbY3oSwumSLfjyyax.jpg","genre_ids":[18],"id":199001,"origin_country":["US"],"ori