INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:Curb','{"page":1,"results":[{"adult":false,"backdrop_path":"/t97VtC5qvra5GThnNBCXHJFnmXg.jpg","genre_ids":[35],"id":4546,"origin_country":["US"],"original_language":"en","original_name":"Curb Your Enthusiasm","overview":"The off-kilter, unscripted comic vision of Larry David, who plays himself in a parallel universe in which he can''t seem to do anything right, and, by his standards, neither can anyone else.","popularity":57.995,"poster_path":"/mZqWmSq1M61Jlre3furVDSXvdrN.jpg","first_air_date":"2000-10-15","name":"Curb Your Enthusiasm","vote_average":8.031,"vote_count":898},{"adult":false,"backdrop_path":"/7cVktgybWLjz52gsKwBtuxlrPaP.jpg","genre_ids":[],"id":24454,"origin_country":["US"],"original_language":"en","original_name":"Curb Appeal","overview":"","popularity":0.9145,"poster_path":"/h4NYz1k0ikUWLKVG9WCwfk0p1s9.jpg","first_air_date":"1999-09-30","name":"Curb Appeal","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/49QfDGEKXHxp4pZcRVqLDj4pDdL.jpg","genre_ids":[10764],"id":133191,"origin_country":["US"],"original_language":"en","original_name":"Curb Appeal Xtreme","overview":"Designer John Gidding, Horticulturalist Jamie Durie, and Carpenter Rachel Taylor join forces to dramatically overhaul the front and backyards of homes. They tackle the most challenging and extreme exterior projects to maximize any property''s potential.","popularity":0.225,"poster_path":"/cr9p5h0iQ8qXgtU5YmTAGfCgtDx.jpg","first_air_date":"2021-09-09","name":"Curb Appeal Xtreme","vote_average":4,"vote_count":2},{"adult":false,"backdrop_path":null,"genre_ids":[],"id":31671,"origin_country":["US"],"original_language":"en","original_name":"Curb Appeal","overview":"Curb Appeal is a half-hour TV series that has aired on HGTV in the United States from 2002 to the present, exploring how a house''s outside \"curb appeal\" will be updated. Various hosts over the years, talk the viewer through the planned improvements. Originally the new look was imagined by drawing the proposed changes over a still picture of the exterior but now computer-generated visualizations are created. Changes include painting, landscaping, and fences, as well as pruning or removing overgrown shrubs, and sometimes cutting down good trees.\n\nJohn Gidding is now the only host and more recent episodes involve multiple homes in an San Francisco Bay Area block, and are titled Curb Appeal. There has also been at least one hour-long Christmas special titled A Very Merry Curb Appeal, with two homes adorned with Christmas decorations.","popularity":0.0322,"poster_path":null,"first_air_date":"","name":"Curb Appeal","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/9sFgNVPn5UCSDprzK5y5EVtca3m.jpg","genre_ids":[10764],"id":123773,"origin_country":["US"],"original_language":"en","original_name":"Curb Appeal: The Block","overview":"A team of home experts dramatically overhauls the exterior of one home and then makes their way down the street, providing smaller-scale makeovers to create instant impact and add value to the entire block.","popularity":0.0439,"poster_path":"/upgl180bENo3bfEs4bfPp7Nu1jH.jpg","first_air_date":"2010-01-01","name":"Curb Appeal: The Block","vote_average":0,"vote_count":0}],"total_pages":1,"total_results":5}','2026-04-08 05:40:38');
INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('show:4546','{"adult":false,"backdrop_path":"/t97VtC5qvra5GThnNBCXHJFnmXg.jpg","created_by":[{"id":16376,"credit_id":"52576f19760ee36aaa452ef8","name":"Larry David","original_name":"Larry David","gender":2,"profile_path":"/ojPx93eaDcanOVi4AH14uAFwXhn.jpg"}],"episode_run_time":[],"first_air_date":"2000-10-15","genres":[{"id":35,"name":"Comedy"}],"homepage":"http://www.hbo.com/curb-your-enthusiasm/","id":4546,"in_production":false,"languages":["en"],"last_air_date":"2024-04-07","last_episode_to_air":{"id":4998036,"name":"No Lessons Learned","overview":"Larry returns to Atlanta, where he gets involved in Richard''s love life and reveals a secret about Cheryl.","vote_average":8.9,"vote_count":8,"air_date":"2024-04-07","episode_number":10,"episode_type":"finale","production_code":"","runtime":53,"season_number":12,"show_id":4546,"still_path":"/bsckMmhv2YFDXRgNSIfYepp4uC.jpg"},"name":"Curb Your Enthusiasm","next_episode_to_air":null,"networks":[{"id":49,"logo_path":"/tuomPhY2UtuPTqqFnKMVHvSb724.png","name":"HBO","origin_country":"US"}],"number_of_episodes":120,"number_of_seasons":12,"origin_country":["US"],"original_language":"en","original_name":"Curb Your Enthusiasm","overview":"The off-kilter, unscripted comic vision of Larry David, who plays himself in a parallel universe in which he can''t seem to do anything right, and, by his standards, neither can anyone else.","popularity":57.995,"poster_path":"/mZqWmSq1M61Jlre3furVDSXvdrN.jpg","production_companies":[{"id":3268,"logo_path":"/tuomPhY2UtuPTqqFnKMVHvSb724.png","name":"HBO","origin_country":"US"},{"id":8803,"logo_path":null,"name":"Production Partners","origin_country":""}],"production_countries":[{"iso_3166_1":"US","name":"United States of America"}],"seasons":[{"air_date":"1999-12-01","episode_count":41,"id":13721,"name":"Specials","overview":"","poster_path":"/mu2tj7IbHMjF79tXWMAbv7CSlVN.jpg","season_number":0,"vote_average":0},{"air_date":"2000-10-15","episode_count":10,"id":13716,"name":"Season 1","overview":"Larry David has it all—money, security, famous friends, a nurturing wife, a fabulous Hollywood home. So why is he so intent on making a complete mess out of his life? Just because you''ve made it, doesn''t mean you''ve got it made.","poster_path":"/an2PP01XrCAzSXB8aQaUlUiC69h.jpg","season_number":1,"vote_average":7.8},{"air_date":"2001-09-23","episode_count":10,"id":13715,"name":"Season 2","overview":"Larry David is still himself—much to the chagrin of everyone around him. From cutting a doll''s hair to answering the door on Halloween to tripping a basketball legend, for every action of Larry''s, there''s an opposite and disproportionately outraged reaction.","poster_path":"/w5QYqd6ucj22yolBUdrhV45NCnn.jpg","season_number":2,"vote_average":8},{"air_date":"2002-09-15","episode_count":10,"id":13719,"name":"Season 3","overview":"Larry and his manager Jeff''s investment in a restaurant leads to laughs when it comes to settling on a chef. Meanwhile, Larry gets into his usual assortment of problems—this time involving Christmas tipping, a manger scene, cell phone miscommunication, the ''nanny from hell,'' betraying the confidence of rapper Krazee-Eyez Killa, committing a ''penis faux pas,'' and even using his mother''s death to escape some unsavory invitations.","poster_path":"/bLBDcwar0FB940gzNU5XhiEc2zr.jpg","season_number":3,"vote_average":8},{"air_date":"2004-01-04","episode_count":10,"id":13717,"name":"Season 4","overview":"Larry brings his many quirks and neuroses to the stage after he is cast in a major Broadway production. Meanwhile, as their 10th anniversary approaches, Larry reminds Cheryl of a special ''present'' she promised him when they were engaged.","poster_path":"/phSfnHPqve22EYCKCVcCEO5NdAW.jpg","season_number":4,"vote_average":8.1},{"air_date":"2005-09-25","episode_count":10,"id":13714,"name":"Season 5","overview":"A near-death experience, a revelation about his father and a sandwich named after him prompt Larry to undertake a sentimental journey in search of his roots...and step on a few toes along the way.","poster_path":"/rVrZ2pad3U0sEFTAnZqjzup9R5G.jpg","season_number":5,"vote_average":7.7},{"air_date":"2007-09-09","episode_count":10,"id":13718,"name":"Season 6","overview":"An African American family named the Blacks is displaced by Hurricane Edna and end up moving in with Larry and Cheryl; plus, Larry invents the perfect excuse for missing parties, gets into a conflict with a dry cleaner and steals flowers from a car-crash memorial.","poster_path":"/mKcg3P2bLnxE2suusIbMVa4V2DM.jpg","season_number":6,"vote_average":8.2},{"air_date":"2009-09-20","episode_count":10,"id":13720,"name":"Season 7","overview":"Larry contemplates his future with an ailing Loretta, decides on a novel approach to winning back Cheryl, and reunites with the stars of ''Seinfeld''.","poster_path":"/wNH2skHzKwt6PQRF2YBAOiQBiwV.jpg","season_number":7,"vote_average":8.3},{"air_date":"2011-07-10","episode_count":10,"id":13722,"name":"Season 8","overview":"As \"Single Larry\" continues to navigate the L.A. dating scene, a faulty alibi lands him back in his hometown of New York City for an extended stay—where he proves that faux-pas and character assassinations can occur just as easily in the Big Apple as in Hollywood.","poster_path":"/lY8OrMJH5W9OVN4o61UAm2SpLXO.jpg","season_number":8,"vote_average":8},{"air_date":"2017-10-01","episode_count":10,"id":90336,"name":"Season 9","overview":"Larry has a big idea that elicits promising feedback from a number of prospective investors—until a string of Larry-esque missteps undermines the plan, at least temporarily.","poster_path":"/juOhISBDQUdRKVXjDYss8no1nzM.jpg","season_number":9,"vote_average":7.9},{"air_date":"2020-01-19","episode_count":10,"id":137894,"name":"Season 10","overview":"Larry gets into a series of escalating predicaments as he takes on a major project to spite a new adversary—which proves to be more complicated than he anti