INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:The Testaments','{"page":1,"results":[{"adult":false,"backdrop_path":"/n8fffwUPi9DMxtwDIR6xoGx9ItP.jpg","genre_ids":[18,10765],"id":287527,"origin_country":["US"],"original_language":"en","original_name":"The Testaments","overview":"Growing up in Gilead is all they have ever known. As a new generation of young women grapple with the bleak future that awaits them, they will be forced to search for allies, new and old, to help in their fight for freedom.","popularity":7.5867,"poster_path":"/xVsFopLisBoiKdXXecaNTN4pJ9A.jpg","first_air_date":"2026-04-08","name":"The Testaments","vote_average":5.2,"vote_count":4},{"adult":false,"backdrop_path":"/dXGaX995fsbiqJgFRj0CEJKxZVV.jpg","genre_ids":[16,10759,35,10765],"id":64163,"origin_country":["JP"],"original_language":"ja","original_name":"新妹魔王の契約者","overview":"Toujou Basara is a high school student whose father has suddenly just remarried. His father then departs overseas leaving Basara with two new beautiful step-sisters. Little does he know, his new sisters, Mio and Maria are actually the new Demon Lord and a succubus!? Almost trapped into a life of servitude, Basara forms a reverse contract by accident and ends up becoming Mio''s master! Hijinks ensue as Basara finds himself in one ecchi situation after another. However, Mio''s life is in danger as she is pursued by demons and heroes!","popularity":23.7887,"poster_path":"/4yrW5uBgcx7GSehJotlxWjAD0NQ.jpg","first_air_date":"2015-01-07","name":"The Testament of Sister New Devil","vote_average":7.9,"vote_count":345},{"adult":false,"backdrop_path":"/cpFFzYxQ27Ru6kc7yI9kWgC6jAT.jpg","genre_ids":[18],"id":116757,"origin_country":["RU"],"original_language":"ru","original_name":"Завещание Ленина","overview":"The author of The Kolyma Stories and many other works spent 17 years in the terrible GULAG camps on Kolyma. The term that Varlam Tikhonovich received in 1929 was for distributing Lenin''s letter to the congress, in which he criticized Stalin. Nowadays, this letter is called the \"testament of Lenin\"…","popularity":2.6364,"poster_path":"/tzZ5HxwuZ9vXLADJqXvC1XDqGI1.jpg","first_air_date":"2007-06-01","name":"Lenin''s Testament","vote_average":10,"vote_count":1},{"adult":false,"backdrop_path":"/toMxMu5EelgObumSeROejAoaVOJ.jpg","genre_ids":[],"id":43443,"origin_country":["RU"],"original_language":"ru","original_name":"Пётр Первый. Завещание","overview":"Peter the Great: The Testament is a Russian TV series, made in 2011 and based on the novel by Daniil Granin''s \"Evenings with Peter the Great\". The film was produced by Studio 2-B-2 entertainment and was shown on Rossiya 1, the Russian TV channel.","popularity":0.8148,"poster_path":"/hKN7LKWtcToP0hAzAhAjxMnAuaj.jpg","first_air_date":"2011-05-14","name":"Peter the Great: The Testament","vote_average":0,"vote_count":0},{"adult":false,"backdrop_path":"/ulGk4NGlwZaCfpiFIDM49a94Z54.jpg","genre_ids":[99],"id":314973,"origin_country":["BR"],"original_language":"pt","original_name":"O Testamento: O Segredo de Anita Harley","overview":"Anita Harley is the main shareholder of Casas Pernambucanas, one of the most traditional retail chains in the country. This series brings the behind-the-scenes disputes surrounding her inheritance in one of the most complex and intriguing cases in the Brazilian judiciary.","popularity":0.259,"poster_path":"/bf6r91iS1Qj8myrOpMzJQH6Jz2t.jpg","first_air_date":"2026-02-23","name":"The Testament: The Secret of Anita Harley","vote_average":9,"vote_count":2},{"adult":false,"backdrop_path":null,"genre_ids":[99],"id":136987,"origin_country":["HR"],"original_language":"hr","original_name":"Tito - posljednji svjedoci testamenta","overview":"Documentary TV series ''Tito – the Last Witnesses of the Testament'' of film director Lordan Zafranović is an intimate story about the last witnesses Tito''s testament and their lives and Tito''s life in 13 episodes each of 56 minutes duration.","popularity":0.4199,"po