INSERT INTO "tmdb_cache" ("cache_key","data","expires_at") VALUES('search:Machine','{"page":1,"results":[{"adult":false,"backdrop_path":"/c5xAH2dZZVSvGH2D3LoyeAFIKGN.jpg","genre_ids":[10759,18],"id":211172,"origin_country":["FR"],"original_language":"fr","original_name":"Machine","overview":"An action show mixing kung-fu and class war.","popularity":2.5863,"poster_path":"/y60GpQoakoVXFKJDH6lbLOiVanv.jpg","first_air_date":"2024-04-04","name":"Machine","vote_average":6.8,"vote_count":18},{"adult":false,"backdrop_path":"/rJKANgQCrIPJV4a9BXwdw7d3BZr.jpg","genre_ids":[16,35,10759,10765],"id":207564,"origin_country":["JP"],"original_language":"ja","original_name":"自動販売機に生まれ変わった俺は迷宮を彷徨う","overview":"A middle-aged man with only one passion in his life meets a fitting end in a traffic accident. That''s where most stories would end, but instead, this is when his story begins when he''s reborn as what he admired the most in life--a vending machine! But his new lease on life happens in the worst place possible--what can a vending machine do in a monster-infested dungeon when he can''t speak or even move on his own?","popularity":12.189,"poster_path":"/bY6oLDoxDyP7JNLVGjeO3udND4g.jpg","first_air_date":"2023-07-05","name":"Reborn as a Vending Machine, I Now Wander the Dungeon","vote_average":6.9,"vote_count":55},{"adult":false,"backdrop_path":"/hQPxYEoF9e2fpU9BMc3dPKMrCD3.jpg","genre_ids":[16,35,18,10765],"id":130996,"origin_country":["JP"],"original_language":"ja","original_name":"四畳半タイムマシンブルース","overview":"It is August 12th. After the remote control to his boarding house''s only air conditioning unit is inadvertently destroyed by spilled cola, \"I\" devises a plan to return to yesterday in a time machine to recover the remote before it breaks. However, his prankster friend Ozu cannot resist playing with past events, even if it means bringing the universe to the brink of destruction. Now \"I\" finds himself racing through time to avoid disaster.","popularity":11.7775,"poster_path":"/5OA5QH2dCsygjEOAsfp5FLW4Y6Q.jpg","first_air_date":"2022-09-14","name":"The Tatami Time Machine Blues","vote_average":7.769,"vote_count":26},{"adult":false,"backdrop_path":"/d2fJtzoIozDPD3IFFEgp6hi9umM.jpg","genre_ids":[16,10759],"id":14290,"origin_country":["JP"],"original_language":"ja","original_name":"マシンロボ クロノスの大逆襲","overview":"Machine Robo: Revenge of Cronos, also known as Revenge of the Gobots, is a Japanese anime television series produced by Ashi Productions. It ran on TV Tokyo from July 3, 1986 through May 28, 1987.\n\nA large portion of the Machine Robo toy-line was exported and sold by Tonka in America as Gobots and Rock Lords. To date, only 15 episodes of the series have officially been released with English subtitles on three DVDs by Central Park Media.","popularity":5.9551,"poster_path":"/xZ04lwFHOdObMSKm49yzP5PC9kj.jpg","first_air_date":"1986-07-03","name":"Machine Robo: Revenge of Cronos","vote_average":4,"vote_count":3},{"adult":false,"backdrop_path":"/b42LVWh2irrOkMdu1MAoe1xZUuv.jpg","genre_ids":[10759,16],"id":9478,"origin_country":["JP"],"original_language":"ja","original_name":"超獣機神ダンクーガ","overview":"Dancougar - Super Beast Machine God is a super robot anime television series. The show ran for 38 episodes from 4 April 1985 to 17 December 1985 and was produced by Ashi Productions. Although the series was planned for 52 episodes, it was ended abruptly before a finale could be reached. Despite this, the series garnered enough popularity for the development of multiple OVA''s. Juusenki Tai Songs featured music videos of the various theme and insert songs from the series to TV series footage. The 1986 OVA Requiem for Victims featured a recap of the television series and a newly-animated conclusion to the story. Additionally, there was a 1987 sequel OVA God Bless Dancouga. In 1989 the four-part Blazing Epilogue OVA series presented a new sequel.","popularity":6.7568,"poster_path":"/jWmPAZVrg0HnspJB9yEuzbHQNpk.jpg","first_air_date":"1985-04-05","name":"Dancougar – Super Beast Machine God","vote_average":5.5,"vote_count":4},{"adult":false,"backdrop_path":"/qKgOxKuZANWLU8jHnf7cmm7R9mf.jpg","genre_ids":[16,35,18],"id":63088,"origin_country":["JP"],"original_language":"ja","original_name":"青春×機関銃","overview":"When Hotaru moves into a new apartment alone, there''s a mysterious man standing nearby the apartment. Hotaru decides to confront the man, who turns out to live in the neighboring apartment. The next day at school, Hotaru''s best friend Kanae tells Hotaru that a host tricked her out of her money. When Hotaru goes to confront the host, he happens to be none other than Hotaru''s neighbor, Masamune?!","popularity":4.78,"poster_path":"/8PNOj3WJ91rgBnLTe7UeSsAYTjL.jpg","first_air_date":"2015-07-03","name":"Aoharu x Machinegun","vote_average":7.568,"vote_count":37},{"adult":false,"backdrop_path":"/5KrC0kondGLZ6cgZNrOazPYSXGb.jpg","genre_ids":[10762,16,10751,35],"id":64198,"origin_country":["CA","US"],"original_language":"en","original_name":"Blaze and the Monster Machines","overview":"AJ is an 8-year-old techie who drives monster-truck Blaze, the top racer in Axle City. The two go on adventures that have them taking on problems involving science and math. Many predicaments they face are caused by Blaze''s rival, Crusher, a tractor-trailer that will do anything to beat other vehicles to the finish line. The animated series is billed as the first TV show for preschoolers to comprehensively cover areas of science, technology, engineering and math. Each episode introduces different STEM concepts, including buoyancy and trajectory.","popularity":23.6009,"poster_path":"/5DzjYIdgoePjMlmS7RCyUYWhpIK.jpg","first_air_date":"2014-10-13","name":"Blaze and the Monster Machines","vote_average":7.4,"vote_count":55},{"adult":false,"backdrop_path":"/shBO7ODPQKX1Cd1Z7OlK7pbUynN.jpg","genre_ids":[16],"id":20183,"origin_country":["JP"],"original_language":"ja","original_name":"ブロッカー軍団IV マシーンブラスター","overview":"Blocker Gundan 4 Machine Blaster is an anime series aired from 1976 to 1977 in Japan. There are 38 episodes aired at 25 minutes each. It is also known as \"Blocker Army IV Machine Blaster\", \"Blocker Corps IV\", \"Blocker Army IV\", \"Blocker Corps\", \"Machine Blaster\" and in Italian version as \"Astrorobot Contatto Ypsilon\".","popularity":3.4895,"poster_path":"/kGZzoFimqCxflm3P7tJmZqdGACE.jpg","first_air_date":"1976-07-05","name":"Blocker Gundan 4 Machine Blaster","vote_average":6.8,"vote_count":4},{"adult":false,"backdrop_path":"/k6gVdNL909okGl5BraTbwvOkkQP.jpg","genre_ids":[16,10759,10765],"id":68640,"origin_country":["JP"],"original_language":"ja","original_name":"機巧少女〈マシンドール〉は傷つかない","overview":"During the early 20th century, along with technological advancements, scientists were able to develop sophisticated magic. The combination of science and sorcery was Makinot, circuits made from spells that were put into objects to bring them to life and even gain a personality. It was developed as a military weapon and has now spread throughout the world. Akabane Raishin is now attending the Royal Academy to become the best in the world. Accompanied by the lovely teenage girl Yaya, who is actually Raishin’s puppet weapon, he plans on rocketing to the top of the class. However, his test scores come nearly dead last although his combat skills and determination are second to none. Raishin has to compete with the deadliest of classmates if he wants to come out as the king.","popularity":4.0333,"poster_path":"/hVZEHhtunEvFHUZGyIZChdci6Ul.jpg","first_air_date":"2013-10-07","name":"Unbreakable Machine-Doll","vote_average":6.1,"vote_count":27},{"adult":false,"backdrop_path":"/rXBA3926SpMlDgwCKkTy3rbsDbO.jpg","genre_ids":[16,10759],"id":16810,"origin_country":["JP"],"original_language":"ja","original_name":"出撃!マシンロボレスキュー","overview":"Machine Robo Rescue was a Japanese anime television series produced by Sunrise and the most recent Machine Robo series to date. A total of 53 episodes and a two-episode special were aired on TV Tokyo from January 8, 2003 to January 3, 2004. The series was inspired by the Machine Robo toyline from Bandai.","popularity":3.9449,"poster_path":"/xmw6HBLjKYcI83Dc2UUHKe4Mg1V.jpg","first_air_date":"2003-01-08","name":"Shutsugeki! Machine Robo Rescue","vote_average":4.5,"vote_count":2},{"adult":false,"backdrop_path":"/vpovnc98qwUNbzDqXmeWWdl64ED.jpg","genre_ids":[35],"id":64413,"origin_country":["SE"],"original_language":"sv","original_name":"Boy Machine","overview":"Eighteen years ago they were the biggest boyband in the world. Now it''s time to reunite.","popularity":0.2666,"poster_path":"/qAgox00MZnBvVuawMJUxox9n5P9.jpg","first_air_date":"2015-10-16","name":"Boy Machine","vote_average":7,"vote_count":2},{"adult":false,"backdrop_path":"/jgOHwX30hyBiQ15rHqF9p4Auhod.jpg","genre_ids":[10759,18],"id":35683,"origin_country":["JP"],"original_language":"ja","original_name":"セーラー服と機関銃","overview":"High school student Hoshi Izumi loses her father suddenly in an accident. One day, Sakuma, the waka gashira of a small and weak Yakuza gang in Asakusa - the Medaka Gumi - pays Izumi a visit along with the gang members. The death of their former kumicho (Boss) puts Medaka Gumi on the verge of a breakup. Therefore, Sakuma begs Izumi, the former boss''s only distant relative left, to succeed to the kumicho position. Izumi is taken by surprise and keeps refusing at first. However, she ends up becoming the 8th kumicho of the Medaka Gumi! The police tell her that her father''s death may possibly be a homicide case. There''s also Mayumi, a mysterious woman staring closely at Izumi''s father''s photograph at his funeral. The situation becomes complicated when the drug-dealing vicious yakuza, Hamaguchi Gumi, comes into the picture as well as Sandaiji Hajime, a politician whose public stance is to eliminate drugs.","popularity":2.8473,"poster_path":"/srTrO41dx62HMgxlJbmM8NlEEHF.jpg","first_air_date":"2006-10-13","name":"Sailor Suit and Machine Gun","vote_averag